#include <OneWire.h>
#include <DallasTemperature.h>
#include <Wire.h>
#include <Adafruit_BMP280.h>
#include <AccelStepper.h>
#include <SD.h>
#define OW_PIN 2
#define HEATER_PIN 9
#define SD_CS 10
#define STEP_PIN 4
#define DIR_PIN 5
#define N_VOL 6
#define N_TEMP 2
#define EQUIL_MS 30000UL
#define FAULT_P 200000.0f
#define N_MOL 0.00082f
OneWire ow(OW_PIN); DallasTemperature ds(&ow);
Adafruit_BMP280 bmp; AccelStepper stp(1,STEP_PIN,DIR_PIN);
File lg;
float vols[N_VOL]={20,26,32,38,44,50};
float temps[N_TEMP]={25.0f,50.0f};
float ideal_gas_validator(float P,float V,float T,float n){
  float V_m3=V*1e-6f; float nRT=n*8.314f*T;
  return (nRT>0)?(P*V_m3)/nRT:-1.0f;
}
void initHardware(){
  ds.begin();bmp.begin();stp.setMaxSpeed(200);stp.setAcceleration(100);
  pinMode(HEATER_PIN,OUTPUT);SD.begin(SD_CS);
  lg=SD.open("pvt.csv",FILE_WRITE);
  if(lg)lg.println("T_C,V_cm3,P_Pa,Z");
  Serial.begin(9600);
}
float readTemperatureSensor(){ds.requestTemperatures();return ds.getTempCByIndex(0);}
float readPressureSensor(){return bmp.readPressure();}
void heaterBangBang(float sp,float pv){analogWrite(HEATER_PIN,(pv<sp-0.5f)?180:0);}
void moveSyringe(float target_mL,float*cur_mL){
  float delta=target_mL-*cur_mL;
  long steps=(long)(delta*1000.0f);
  stp.move(steps);while(stp.run());*cur_mL=target_mL;
}
void checkFaultSafety(float P){if(P>FAULT_P){analogWrite(HEATER_PIN,0);Serial.println("FAULT:OVERPRESSURE");while(1);}}
void setup(){initHardware();}
void loop(){
  static int ti=0,vi=0;static float curML=20.0f;
  static unsigned long eqStart=0;static bool moving=true;
  if(ti>=N_TEMP){lg.close();while(1);}
  float sp=temps[ti];
  float T=readTemperatureSensor();heaterBangBang(sp,T);
  float P=readPressureSensor();checkFaultSafety(P);
  if(moving){moveSyringe(vols[vi],&curML);eqStart=millis();moving=false;}
  if(millis()-eqStart>EQUIL_MS){
    T=readTemperatureSensor();P=readPressureSensor();
    float Z=ideal_gas_validator(P,vols[vi],T+273.15f,N_MOL);
    if(lg){lg.print(T,2);lg.print(',');lg.print(vols[vi],1);lg.print(',');lg.print(P,1);lg.print(',');lg.println(Z,5);lg.flush();}
    Serial.print("Z=");Serial.println(Z,5);
    vi++;if(vi>=N_VOL){vi=0;ti++;moveSyringe(20.0f,&curML);}
    moving=true;
  }
  delay(200);
}
